import React, { useState } from 'react';
import './Contact.css';

export default function Contact() {
  const [form, setForm] = useState({ name: '', email: '', message: '' });

  const set = (key) => (event) => {
    setForm((prev) => ({ ...prev, [key]: event.target.value }));
  };

  return (
    <section className="section contact-section reveal-on-scroll" id="contact">
      <div className="section-inner contact-grid">
        <div className="contact-left">
          <p className="section-label">Contact</p>
          <h2 className="section-title">Let&apos;s Build Something Cinematic</h2>
          <a className="contact-email" href="mailto:abhi@chakrapani.studio">
            abhi@chakrapani.studio
          </a>
        </div>

        <form className="contact-form" onSubmit={(event) => event.preventDefault()}>
          <label className="form-label" htmlFor="name">Name</label>
          <input
            id="name"
            className="form-input"
            placeholder="Your name"
            value={form.name}
            onChange={set('name')}
          />

          <label className="form-label" htmlFor="email">Email</label>
          <input
            id="email"
            className="form-input"
            type="email"
            placeholder="you@example.com"
            value={form.email}
            onChange={set('email')}
          />

          <label className="form-label" htmlFor="message">Message</label>
          <textarea
            id="message"
            className="form-input form-message"
            placeholder="Tell me about your project"
            value={form.message}
            onChange={set('message')}
          />

          <button className="btn btn-gradient" type="submit">Send Inquiry</button>
        </form>
      </div>
    </section>
  );
}
